// PGlite path: read migration files manually and execute each statement
await client.exec(
  'CREATE TABLE IF NOT EXISTS "__drizzle_migrations" (hash text PRIMARY KEY, created_at bigint)',
)
const result = await client.query<{ hash: string }>(
  'SELECT hash FROM "__drizzle_migrations"',
)
const applied = new Set((result.rows ?? []).map((r: { hash: string }) => r.hash))
const migrations = readMigrationFiles({ migrationsFolder: folder })
for (const migration of migrations) {
  if (applied.has(migration.hash)) continue
  for (const sql of migration.sql) {
    await client.exec(sql)
  }
  await client.query('INSERT INTO "__drizzle_migrations" (hash, created_at) VALUES ($1, $2)', [
    migration.hash,
    Date.now(),
  ])
}

