test("applyMigrations is idempotent — second call is a no-op", async () => {
  const client = init(":memory:")
  try {
    await applyMigrations(client) // first run: applies all
    const tablesAfterFirst = await getTables(client)
    expect(tablesAfterFirst).toContain("session")

    // Second call should not throw
    await expect(applyMigrations(client)).resolves.toBeUndefined()

    // Tables unchanged
    const tablesAfterSecond = await getTables(client)
    expect(tablesAfterSecond).toEqual(tablesAfterFirst)

    // Verify tracking table has exactly the right number of rows
    const underlying = (client as any).$client
    const { rows } = await underlying.query(
      'SELECT count(*) as cnt FROM "__drizzle_migrations"',
    )
    expect(rows[0].cnt).toBe(4) // 4 migrations applied exactly once
  } finally {
    const underlying = (client as any).$client
    if (underlying && typeof underlying.end === "function") {
      await underlying.end()
    }
  }
})
